+	if state.LastDispatchAt != "" {
+		t.Errorf("expected empty LastDispatchAt, got %q", state.LastDispatchAt)
+	}
+	if state.LastDispatchCount != 0 {
+		t.Errorf("expected LastDispatchCount=0, got %d", state.LastDispatchCount)
+	}
